// ===== PERSISTENCE (SQLite) =====
// On Railway: set DB_PATH=/data/slopshop.db and mount a volume at /data
// On local: defaults to .data/slopshop.db
const fs = require('fs');
const Database = require('better-sqlite3');
// Try paths in order: DB_PATH env → .data/ → /tmp/
const DB_CANDIDATES = [
  process.env.DB_PATH,
  path.join(__dirname, '.data', 'slopshop.db'),
  '/tmp/slopshop.db',
].filter(Boolean);

let DB_PATH;
let db;
for (const candidate of DB_CANDIDATES) {
  try {
    const dir = path.dirname(candidate);
    if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
    // Touch the file first (Railway volumes need this)
    if (!fs.existsSync(candidate)) fs.writeFileSync(candidate, '');
    // Test by actually opening the database
    db = new Database(candidate);
    DB_PATH = candidate;
    break;
  } catch(e) {
    log.warn('DB path failed, trying next', { path: candidate, error: e.message });
  }
}
if (!db) {
  console.error('FATAL: Could not open database at any path'); console.log('Slopshop shutting down due to missing database');
  process.exit(1);
}
db.pragma('journal_mode = WAL'); // fast concurrent reads
db.pragma('busy_timeout = 5000'); // wait up to 5s for locks instead of failing
db.pragma('synchronous = NORMAL'); // faster writes, still crash-safe with WAL
// Memory-aware SQLite tuning: constrained on Railway (512MB), generous locally
const IS_RAILWAY = !!(process.env.RAILWAY_SERVICE_NAME || process.env.RAILWAY_ENVIRONMENT || process.env.RAILWAY_PROJECT_ID);
db.pragma(`cache_size = ${IS_RAILWAY ? -8000 : -64000}`); // 8MB on Railway, 64MB locally
db.pragma('temp_store = MEMORY'); // PERF: temp tables in memory, not disk
db.pragma(`mmap_size = ${IS_RAILWAY ? 0 : 268435456}`); // disable mmap on Railway to save RSS
db.pragma('page_size = 8192'); // PERF: 8KB pages (better for large tables, only works on new DBs)
log.info('Database initialized', { path: DB_PATH, tables: db.prepare("SELECT count(*) as c FROM sqlite_master WHERE type='table'").get().c });

// Schema migration: drop tables with stale columns so route modules recreate them correctly
// Safe: all DROP TABLE IF EXISTS — only removes tables that exist with wrong schema
try {
  const _staleTables = [
    'agent_identities','ans_registry','a2a_messages','agent_orgs','org_members',
    'workflows','workflow_runs','workflow_run_steps','workflow_templates','workflow_approvals',
    'marketplace_listings','marketplace_installs','marketplace_ratings','marketplace_transactions'
  ];
  const _existingTables = db.prepare("SELECT name FROM sqlite_master WHERE type='table'").all().map(r => r.name);
  let _migrated = 0;
  for (const t of _staleTables) {
    if (_existingTables.includes(t)) {
      // Check if table has expected columns; drop only if schema is stale
      const cols = db.prepare(`PRAGMA table_info(${t})`).all().map(c => c.name);
      let needsDrop = false;
      if (t === 'a2a_messages' && !cols.includes('to_agent')) needsDrop = true;
      if (t === 'workflows' && !cols.includes('api_key')) needsDrop = true;
      if (t === 'marketplace_listings' && !cols.includes('category')) needsDrop = true;
      if (needsDrop) {
        db.exec(`DROP TABLE IF EXISTS ${t}`);
        _migrated++;
      }
    }
  }
  if (_migrated > 0) log.info('Schema migration complete', { dropped: _migrated });
} catch (e) { /* non-fatal */ }

