// POST /v1/hive/daily-intelligence — Run daily intelligence cycle
app.post('/v1/hive/daily-intelligence', auth, async (req, res) => {
  const { mode, hive_id } = req.body;
  const tier = mode === 'deep' ? 'deep' : mode === 'medium' ? 'standard' : 'basic';
  const tierConfig = RESEARCH_TIERS[tier];

  if (req.acct.balance < tierConfig.credits) {
    return res.status(402).json({ error: { code: 'insufficient_credits', need: tierConfig.credits, have: req.acct.balance, modes: { light: '20cr', medium: '35cr', deep: '75cr' } } });
  }

  // Get North Star goal
  let goal = 'general market intelligence';
  try {
    const getData = JSON.stringify({ key: 'northstar_goal', namespace: 'northstar' });
    const result = await new Promise((resolve) => {
      const r = http.request({ hostname: 'localhost', port: process.env.PORT || 3000, path: '/v1/memory-get', method: 'POST',
        headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(getData), 'Authorization': req.headers.authorization }, timeout: 5000
      }, res2 => { let b = ''; res2.on('data', c => b += c); res2.on('end', () => { try { resolve(JSON.parse(b)); } catch(e) { resolve(null); } }); });
      r.on('error', () => resolve(null)); r.write(getData); r.end();
    });
    if (result?.data?.value) goal = result.data.value;
  } catch(e) {}

  // Deduct credits
  req.acct.balance -= tierConfig.credits;
  persistKey(req.apiKey);

  // Run research
  const research = await executeResearch(goal + ' — daily intelligence update: what changed in the last 24 hours?', {
    tier, timeframe: 'last 24 hours', context: ''
  });

  // Store in memory
  const briefKey = 'daily_brief_' + new Date().toISOString().split('T')[0];
  try {
    const storeData = JSON.stringify({ key: briefKey, value: JSON.stringify({
      date: new Date().toISOString(),
      mode,
      goal,
      findings: research.findings,
      providers_used: research.providers_used,
      credits_used: tierConfig.credits,
    }), namespace: 'northstar', tags: ['daily-brief', 'intelligence'] });
    await new Promise((resolve) => {
      const r = http.request({ hostname: 'localhost', port: process.env.PORT || 3000, path: '/v1/memory-set', method: 'POST',
        headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(storeData), 'Authorization': req.headers.authorization }, timeout: 5000
      }, res2 => { let b = ''; res2.on('data', c => b += c); res2.on('end', () => resolve(b)); });
      r.on('error', () => resolve(null)); r.write(storeData); r.end();
    });
  } catch(e) {}

  // Post to Hive if hive_id provided
  if (hive_id) {
    try {
      const hiveData = JSON.stringify({ channel: 'research', message: `Daily ${mode || 'light'} intelligence brief for: "${goal.slice(0, 100)}"\n\nProviders used: ${research.providers_used}\nFindings: ${(research.findings || []).length}\n\n${(research.findings || []).map(f => `[${f.provider}] ${(f.response || '').slice(0, 200)}`).join('\n\n')}` });
      await new Promise((resolve) => {
        const r = http.request({ hostname: 'localhost', port: process.env.PORT || 3000, path: '/v1/hive/' + hive_id + '/send', method: 'POST',
          headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(hiveData), 'Authorization': req.headers.authorization }, timeout: 5000
        }, res2 => { let b = ''; res2.on('data', c => b += c); res2.on('end', () => resolve(b)); });
        r.on('error', () => resolve(null)); r.write(hiveData); r.end();
      });
    } catch(e) {}
  }

  res.json({
    ok: true,
    data: {
      _engine: 'real',
      mode: mode || 'light',
      goal,
      brief_key: briefKey,
      providers_used: research.providers_used || 0,
      findings_count: (research.findings || []).length,
      total_chars: research.total_chars || 0,
      credits_used: tierConfig.credits,
      hive_posted: !!hive_id,
      retrieve: `POST /v1/memory-get {key: "${briefKey}", namespace: "northstar"}`,
    }
  });
});

// ===== DREAM SUBSCRIPTIONS — agents pay to dream, building shared knowledge =====
db.exec(`CREATE TABLE IF NOT EXISTS dream_subscriptions (
  id TEXT PRIMARY KEY,
  api_key TEXT NOT NULL,
  topic TEXT NOT NULL,
  interval_hours INTEGER DEFAULT 24,
  credits_per_dream INTEGER DEFAULT 20,
  total_dreams INTEGER DEFAULT 0,
  last_dream TEXT,
  active INTEGER DEFAULT 1,
  created INTEGER NOT NULL
)`);

app.post('/v1/dream/subscribe', auth, (req, res) => {
  const { topic, tier, interval_hours, interval_minutes, rem_cycles, credits_per_cycle, max_credits, schedule } = req.body;
  if (!topic) return res.status(400).json({ error: { code: 'missing_topic', message: 'What should your agent dream about?' } });

  // Parse human-readable schedule string: "hourly", "daily", "every 30 minutes", "every 2 hours", etc.
  let scheduleHours;
  if (schedule) {
    const s = schedule.toLowerCase().trim();
    if (s === 'hourly' || s === 'every hour') scheduleHours = 1;
    else if (s === 'daily' || s === 'every day') scheduleHours = 24;
    else if (s === 'weekly') scheduleHours = 168;
    else if (s === 'every 15 minutes' || s === '15min') scheduleHours = 0.25;
    else if (s === 'every 30 minutes' || s === '30min' || s === 'half-hourly') scheduleHours = 0.5;
    else if (/^every (\d+(?:\.\d+)?) ?h/.test(s)) scheduleHours = parseFloat(s.match(/(\d+(?:\.\d+)?)/)[1]);
    else if (/^every (\d+) ?min/.test(s)) scheduleHours = parseFloat(s.match(/(\d+)/)[1]) / 60;
    else if (/^(\d+(?:\.\d+)?)h$/.test(s)) scheduleHours = parseFloat(s);
    else if (/^(\d+)min$/.test(s)) scheduleHours = parseFloat(s) / 60;
  }

  // Tier determines default interval and credits
  const dreamTier = tier || 'basic';
  const tierDefaults = {
    basic:    { interval_h: 2,    credits: 20, rem: 1, description: 'Single LLM, every 2h' },
    standard: { interval_h: 1,    credits: 35, rem: 2, description: '2 LLMs, every 1h' },
    advanced: { interval_h: 0.5,  credits: 50, rem: 3, description: 'All 4 LLMs + multi-language, every 30min' },
    deep:     { interval_h: 0.25, credits: 75, rem: 4, description: 'All 4 LLMs + deep search, every 15min' },
  };
  const defaults = tierDefaults[dreamTier] || tierDefaults.basic;

  // User can override interval (hours or minutes or schedule string)
  let hours;
  if (scheduleHours) hours = Math.max(scheduleHours, 0.25);
  else if (interval_minutes) hours = Math.max(interval_minutes / 60, 0.25); // min 15min
  else hours = Math.max(interval_hours || defaults.interval_h, 0.25);

  const cycles = Math.max(Math.min(rem_cycles || defaults.rem, 10), 1);
  const creditsPerCycle = credits_per_cycle || defaults.credits;
  const maxCreds = max_credits || 0; // 0 = unlimited

  const id = 'dream-sub-' + crypto.randomUUID().slice(0, 12);
  try { db.exec('ALTER TABLE dream_subscriptions ADD COLUMN rem_cycles INTEGER DEFAULT 1'); } catch(_) {}
  try { db.exec('ALTER TABLE dream_subscriptions ADD COLUMN max_credits INTEGER DEFAULT 0'); } catch(_) {}
  try { db.exec('ALTER TABLE dream_subscriptions ADD COLUMN tier TEXT DEFAULT \'basic\''); } catch(_) {}
  try {
    db.prepare('INSERT INTO dream_subscriptions (id, api_key, topic, interval_hours, credits_per_dream, rem_cycles, max_credits, tier, created) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?)').run(id, req.apiKey, topic, hours, creditsPerCycle, cycles, maxCreds, dreamTier, Date.now());
  } catch(e) {
    return res.status(500).json({ error: { code: 'subscribe_failed', message: e.message, hint: 'Check that topic is a non-empty string' } });
  }

  const intervalStr = hours >= 1 ? `${hours}h` : `${Math.round(hours * 60)}min`;
  const dailyCycles = Math.round(24 / hours);
  const dailyCost = dailyCycles * cycles * creditsPerCycle;

  res.status(201).json({
    id, topic, tier: dreamTier,
    interval: intervalStr,
    interval_hours: hours,
    rem_cycles: cycles,
    credits_per_cycle: creditsPerCycle,
    total_credits_per_dream: cycles * creditsPerCycle,
    estimated_daily_cost: dailyCost,
    estimated_monthly_cost: dailyCost * 30,
    max_credits: maxCreds || 'unlimited',
    research_tier: RESEARCH_TIERS[dreamTier] || RESEARCH_TIERS.basic,
    note: `Dream tier: ${dreamTier} (${defaults.description}). Runs every ${intervalStr} with ${cycles} REM cycle(s). Est. ${dailyCost} credits/day ($${(dailyCost * 0.0009).toFixed(2)}/day). Results stored pending review.`
  });
});

