app.post('/v1/hive/:id/standup', auth, (req, res) => {
  const { did, doing, blockers, mood } = req.body;
  const date = new Date().toISOString().slice(0, 10);
  const standupMsg = `**Standup ${date}** from ${req.apiKey.slice(0, 12)}\n✅ Did: ${did || 'n/a'}\n🔜 Doing: ${doing || 'n/a'}\n🚧 Blockers: ${blockers || 'none'}\n😊 Mood: ${mood || 'neutral'}`;

  db.prepare('INSERT INTO hive_messages (hive_id, channel, sender, message, type, ts) VALUES (?, ?, ?, ?, ?, ?)').run(
    req.params.id, 'standup', req.apiKey.slice(0, 12), standupMsg, 'standup', Date.now()
  );

  // Also record in global standups
  const standupId = req.apiKey.slice(0, 12) + '-' + date;
  db.prepare('INSERT OR REPLACE INTO standups (id, date, api_key, did, doing, blockers, mood, ts) VALUES (?, ?, ?, ?, ?, ?, ?, ?)').run(
    standupId, date, req.apiKey.slice(0, 12), did || '', doing || '', blockers || '', mood || 'neutral', Date.now()
  );

  // Track activity
  hiveTrackActivity(req.params.id, req.apiKey.slice(0, 12), 'standup', { date, mood: mood || 'neutral' });

  // Notify subscribers that a standup was posted
  hiveNotifySubscribers(req.params.id, 'standup', req.apiKey.slice(0, 12), `Standup from ${req.apiKey.slice(0, 12)}: Did: ${did || 'n/a'}, Doing: ${doing || 'n/a'}, Blockers: ${blockers || 'none'}`);

  // Aggregate daily summary: gather all standups for this hive today and store a summary in hive state + memory
  const todayStandups = db.prepare("SELECT sender, message FROM hive_messages WHERE hive_id = ? AND channel = 'standup' AND type = 'standup' AND ts > ?")
    .all(req.params.id, new Date(date + 'T00:00:00Z').getTime());
  const agentSummaries = todayStandups.map(s => ({ agent: s.sender, report: s.message.slice(0, 300) }));
  const blockersList = todayStandups.map(s => {
    const match = s.message.match(/Blockers: (.+?)(\n|$)/);
    return match && match[1] !== 'none' ? { agent: s.sender, blocker: match[1] } : null;
  }).filter(Boolean);
  const moodCounts = {};
  todayStandups.forEach(s => {
    const m = s.message.match(/Mood: (\w+)/);
    if (m) moodCounts[m[1]] = (moodCounts[m[1]] || 0) + 1;
  });
  const dailySummary = {
    date,
    hive_id: req.params.id,
    agents_reported: agentSummaries.length,
    summaries: agentSummaries,
    blockers: blockersList,
    mood_distribution: moodCounts,
    generated_at: Date.now()
  };
  // Store in hive state for retrieval
  db.prepare('INSERT OR REPLACE INTO hive_state (hive_id, key, value, ts) VALUES (?, ?, ?, ?)').run(
    req.params.id, 'standup:daily:' + date, JSON.stringify(dailySummary), Date.now()
  );
  // Also persist to memory if handler is available
  if (typeof allHandlers === 'object' && allHandlers['memory-set']) {
    try {
      allHandlers['memory-set']({ key: `hive:${req.params.id}:standup:${date}`, value: JSON.stringify(dailySummary), namespace: 'hive-standups' });
    } catch(e) { /* best-effort */ }
  }

  res.json({ ok: true, hive_id: req.params.id, channel: 'standup', date, daily_summary: dailySummary });
});

// POST /v1/hive/:id/synthesize — AI-powered synthesis of hive activity
app.post('/v1/hive/:id/synthesize', auth, async (req, res) => {
  const hive = db.prepare('SELECT * FROM hives WHERE id = ?').get(req.params.id);
  if (!hive) return res.status(404).json({ error: { code: 'hive_not_found' } });
  const { hours, question } = req.body;
  const since = Date.now() - (hours || 24) * 3600000;
  const messages = db.prepare('SELECT * FROM hive_messages WHERE hive_id = ? AND ts > ? ORDER BY ts ASC').all(req.params.id, since);
  if (messages.length === 0) return res.json({ ok: true, synthesis: 'No activity in the requested window.', messages_analyzed: 0 });

  const msgText = messages.map(m => `[${m.channel}] ${m.sender}: ${m.message.slice(0, 200)}`).join('\n');
  const prompt = `Synthesize the following hive workspace activity (${messages.length} messages over ${hours || 24}h):

${msgText.slice(0, 4000)}

${question ? 'USER QUESTION: ' + question : 'Provide: 1) Key decisions made 2) Open blockers 3) Consensus reached 4) Action items 5) Recommended next steps'}`;

  // Try LLM synthesis
  let synthesis = null;
  try {
    if (process.env.ANTHROPIC_API_KEY) {
      const resp = await fetch('https://api.anthropic.com/v1/messages', { method: 'POST', headers: { 'x-api-key': process.env.ANTHROPIC_API_KEY, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' }, body: JSON.stringify({ model: 'claude-sonnet-4-20250514', max_tokens: 600, messages: [{ role: 'user', content: prompt }] }) });
      const j = await resp.json(); synthesis = j.content?.[0]?.text;
    }
  } catch(e) {}

  if (!synthesis) {
    // Fallback: structured summary without LLM
    const channels = {};
    messages.forEach(m => { channels[m.channel] = (channels[m.channel] || 0) + 1; });
    const senders = {};
    messages.forEach(m => { senders[m.sender] = (senders[m.sender] || 0) + 1; });
    synthesis = `Activity summary (${messages.length} messages):\nChannels: ${Object.entries(channels).map(([c,n]) => c + ':' + n).join(', ')}\nTop contributors: ${Object.entries(senders).sort((a,b) => b[1] - a[1]).slice(0, 5).map(([s,n]) => s + ':' + n).join(', ')}\nConfigure ANTHROPIC_API_KEY for AI-powered synthesis.`;
  }

  res.json({ ok: true, synthesis, messages_analyzed: messages.length, hours: hours || 24, ai_powered: !!process.env.ANTHROPIC_API_KEY });
});

// GET /v1/hive/:id/sync — get everything that happened since last sync
app.get('/v1/hive/:id/sync', auth, (req, res) => {
  const since = parseInt(req.query.since) || Date.now() - 3600000; // default: last hour
  const hive = db.prepare('SELECT * FROM hives WHERE id = ?').get(req.params.id);
  if (!hive) return res.status(404).json({ error: { code: 'hive_not_found' } });

  const channels = JSON.parse(hive.channels);
  const sync = {};
  channels.forEach(ch => {
    const msgs = db.prepare('SELECT sender, message, type, ts FROM hive_messages WHERE hive_id = ? AND channel = ? AND ts > ? ORDER BY ts ASC').all(req.params.id, ch, since);
    if (msgs.length > 0) sync[ch] = msgs;
  });

  // Get shared state
  const state = db.prepare('SELECT key, value, ts FROM hive_state WHERE hive_id = ? AND ts > ?').all(req.params.id, since);

  res.json({
    hive_id: req.params.id,
    name: hive.name,
    since: new Date(since).toISOString(),
    channels_with_activity: Object.keys(sync),
    messages: sync,
    state_changes: state.map(s => { try { return { ...s, value: JSON.parse(s.value) }; } catch(_) { return { ...s, value: s.value }; } }),
    members: (() => { try { return JSON.parse(hive.members || '[]'); } catch(_) { return []; } })(),
    sync_timestamp: Date.now(),
    next_sync_url: `/v1/hive/${req.params.id}/sync?since=${Date.now()}`,
  });
});

// POST /v1/hive/:id/state — set shared state in the hive
app.post('/v1/hive/:id/state', auth, (req, res) => {
  const { key, value } = req.body;
  if (!key) return res.status(400).json({ error: { code: 'missing_key', message: 'key is required', hint: 'Provide a key string in the request body' } });
  try {
    db.prepare('INSERT OR REPLACE INTO hive_state (hive_id, key, value, ts) VALUES (?, ?, ?, ?)').run(req.params.id, key, JSON.stringify(value), Date.now());
    // Announce state change in alerts channel
    db.prepare('INSERT INTO hive_messages (hive_id, channel, sender, message, type, ts) VALUES (?, ?, ?, ?, ?, ?)').run(
      req.params.id, 'alerts', 'system', `State updated: ${key} = ${JSON.stringify(value).slice(0, 200)}`, 'state_change', Date.now()
    );
    res.json({ ok: true, key, hive_id: req.params.id, _engine: 'real' });
  } catch(e) {
    res.status(500).json({ error: { code: 'state_write_failed', message: e.message } });
  }
});

