db.exec(`CREATE TABLE IF NOT EXISTS reputation_slashes (
  id TEXT PRIMARY KEY,
  agent_id TEXT NOT NULL,
  slashed_by TEXT NOT NULL,
  reason TEXT NOT NULL,
  evidence TEXT NOT NULL,
  amount REAL DEFAULT 1.0,
  ts INTEGER NOT NULL
)`);
