// GET /v1/agent/templates — List all available swarm templates
app.get('/v1/agent/templates', auth, (req, res) => {
  const start = Date.now();
  try {
    const templates = Object.values(AGENT_TEMPLATES).map(t => ({
      id: t.id,
      name: t.name,
      description: t.description,
      agent_count: t.agents.length,
      step_count: t.steps.length,
      estimated_credits: t.estimated_credits,
      agents: t.agents.map(a => ({ role: a.role, purpose: a.purpose, tools: a.tools })),
      steps: t.steps,
    }));

    const latency = Date.now() - start;
    dbInsertAudit.run(new Date().toISOString(), req.apiKey.slice(0, 12) + '...', 'agent/templates', 0, latency, 'real');
    res.json({
      ok: true,
      templates,
      count: templates.length,
      _engine: 'real',
      _latency_ms: latency,
    });
  } catch (e) {
    log.error('agent/templates failed', { error: e.message });
    res.status(500).json({ error: { code: 'internal_error', message: e.message } });
  }
});

// POST /v1/agent/template/run — Deploy a swarm from a template
// Helper: safely call a handler, return { status, output } or { status, error }
async function _tplCall(slug, input, req) {
  const handler = allHandlers[slug];
  if (!handler || typeof handler !== 'function') return { status: 'unavailable', error: slug + ' handler not loaded' };
  try {
    const result = await handler(input, req);
    return { status: 'ok', output: result };
  } catch (err) {
    return { status: 'error', error: err.message };
  }
}

// Template-specific execution pipelines that ACTUALLY chain real handler calls
const TEMPLATE_RUNNERS = {
  // ---------- TRUTH-SEEKER ----------
  'truth-seeker': async (task, params, req) => {
    const steps = [];
    let phase1Result = null;

    // Phase 1: Research — use llm-think if available, else fallback to keyword-extract + memory-search
    const p1Start = Date.now();
    if (allHandlers['llm-think']) {
      const res1 = await _tplCall('llm-think', { prompt: 'Research the following topic thoroughly. Identify key claims, evidence, and counter-arguments:\n\n' + task, ...(params || {}) }, req);
      phase1Result = res1.output;
      steps.push({ phase: 'research', description: 'Primary research via llm-think', duration_ms: Date.now() - p1Start, tools_called: [{ tool: 'llm-think', ...res1 }] });
    } else {
      // Fallback: extract keywords then search memory
      const kwRes = await _tplCall('text-keyword-extract', { text: task }, req);
      const keywords = (kwRes.output && kwRes.output.keywords) ? kwRes.output.keywords.join(' ') : task;
      const memRes = await _tplCall('memory-search', { query: keywords, ...(params || {}) }, req);
      phase1Result = { keywords: kwRes.output, memory_results: memRes.output };
      steps.push({ phase: 'research', description: 'Fallback research via text-keyword-extract + memory-search (no LLM available)', duration_ms: Date.now() - p1Start, tools_called: [{ tool: 'text-keyword-extract', ...kwRes }, { tool: 'memory-search', ...memRes }] });
    }

    // Phase 2: Critique — call llm-think with critique prompt including phase 1 results
    const p2Start = Date.now();
    let phase2Result = null;
    if (allHandlers['llm-think']) {
      const critiquePrompt = 'You are a rigorous fact-checker and critic. Below are research findings on the topic: "' + task + '".\n\n' +
        'FINDINGS:\n' + JSON.stringify(phase1Result, null, 2).slice(0, 6000) + '\n\n' +
        'Please:\n1. Identify any unsupported claims or logical fallacies\n2. Note what evidence is missing\n3. Provide a balanced synthesis of what is well-supported vs. uncertain';
      const res2 = await _tplCall('llm-think', { prompt: critiquePrompt, ...(params || {}) }, req);
      phase2Result = res2.output;
      steps.push({ phase: 'critique', description: 'Critical analysis of research findings via llm-think', duration_ms: Date.now() - p2Start, tools_called: [{ tool: 'llm-think', ...res2 }] });
    } else {
      phase2Result = { synthesis: 'LLM unavailable — raw research returned as-is', research: phase1Result };
      steps.push({ phase: 'critique', description: 'Critique skipped (no LLM available)', duration_ms: Date.now() - p2Start, tools_called: [] });
    }

    // Phase 3: Store final synthesis in memory
    const p3Start = Date.now();
    const synthesis = typeof phase2Result === 'string' ? phase2Result : JSON.stringify(phase2Result);
    const memRes = await _tplCall('memory-set', { key: 'truth-seeker-' + Date.now(), value: synthesis.slice(0, 2000), namespace: 'truth-seeker' }, req);
    steps.push({ phase: 'store', description: 'Store final synthesis in memory', duration_ms: Date.now() - p3Start, tools_called: [{ tool: 'memory-set', ...memRes }] });

    return { steps, final_output: phase2Result };
  },

  // ---------- DEBUGGER ----------
  'debugger': async (task, params, req) => {
    const steps = [];
    const code = (params && params.code) || task;

    // Phase 1: Code complexity scoring
    const p1Start = Date.now();
    const complexRes = await _tplCall('code-complexity-score', { code }, req);
    steps.push({ phase: 'analyze', description: 'Static complexity analysis via code-complexity-score', duration_ms: Date.now() - p1Start, tools_called: [{ tool: 'code-complexity-score', ...complexRes }] });

    // Phase 2: Execute the code to test it
    const p2Start = Date.now();
    const execRes = await _tplCall('exec-javascript', { code }, req);
    steps.push({ phase: 'test', description: 'Runtime test via exec-javascript', duration_ms: Date.now() - p2Start, tools_called: [{ tool: 'exec-javascript', ...execRes }] });

    // Phase 3: Summarize findings — use llm-think if available, else build a structured summary
    const p3Start = Date.now();
    let summary;
    if (allHandlers['llm-think']) {
      const summaryPrompt = 'Summarize debugging findings for this code:\n\nCOMPLEXITY ANALYSIS:\n' +
        JSON.stringify(complexRes.output, null, 2).slice(0, 3000) + '\n\nEXECUTION RESULT:\n' +
        JSON.stringify(execRes.output, null, 2).slice(0, 3000) + '\n\nProvide: 1) Key issues found 2) Risk assessment 3) Suggested fixes';
      const sumRes = await _tplCall('llm-think', { prompt: summaryPrompt, ...(params || {}) }, req);
      summary = sumRes.output;
      steps.push({ phase: 'summarize', description: 'AI-powered summary of findings via llm-think', duration_ms: Date.now() - p3Start, tools_called: [{ tool: 'llm-think', ...sumRes }] });
    } else {
      summary = {
        complexity: complexRes.output,
        execution: execRes.output,
        verdict: complexRes.status === 'ok' && execRes.status === 'ok' ? 'Code analyzed and executed successfully' : 'Issues detected — see details above'
      };
      steps.push({ phase: 'summarize', description: 'Structured summary (no LLM)', duration_ms: Date.now() - p3Start, tools_called: [] });
    }

    return { steps, final_output: summary };
  },

  // ---------- DATA-PIPELINE ----------
  'data-pipeline': async (task, params, req) => {
    const steps = [];
    const inputData = (params && params.data) || task;

    // Phase 1: Parse input — detect CSV vs JSON and use appropriate handler
    const p1Start = Date.now();
    let parsed = null;
    let parseToolUsed = null;

    const looksLikeCsv = typeof inputData === 'string' && inputData.includes(',') && inputData.includes('\n');
    if (looksLikeCsv) {
      const csvRes = await _tplCall('text-csv-to-json', { csv: inputData, ...(params || {}) }, req);
      parsed = csvRes.output;
      parseToolUsed = { tool: 'text-csv-to-json', ...csvRes };
    } else {
      const jsonInput = typeof inputData === 'string' ? inputData : JSON.stringify(inputData);
      const jsonRes = await _tplCall('text-json-to-csv', { json: jsonInput, ...(params || {}) }, req);
      parsed = jsonRes.output;
      parseToolUsed = { tool: 'text-json-to-csv', ...jsonRes };
    }
    steps.push({ phase: 'parse', description: 'Parse input data (' + (looksLikeCsv ? 'CSV->JSON' : 'JSON->CSV') + ')', duration_ms: Date.now() - p1Start, tools_called: [parseToolUsed] });

    // Phase 2: Transform data — use llm-think if available for intelligent transform, else passthrough
    const p2Start = Date.now();
    let transformed = parsed;
    if (allHandlers['llm-think']) {
      const transformPrompt = 'You are a data transformation engine. Given this parsed data, clean it, remove nulls/duplicates, normalize field names, and return the improved data as JSON.\n\nDATA:\n' +
        JSON.stringify(parsed, null, 2).slice(0, 6000) + '\n\nReturn only the cleaned JSON.';
      const tRes = await _tplCall('llm-think', { prompt: transformPrompt, ...(params || {}) }, req);
      transformed = tRes.output;
      steps.push({ phase: 'transform', description: 'AI-powered data transformation via llm-think', duration_ms: Date.now() - p2Start, tools_called: [{ tool: 'llm-think', ...tRes }] });
    } else {
      transformed = { data: parsed, _transformed: true, _note: 'passthrough (no LLM available)' };
      steps.push({ phase: 'transform', description: 'Passthrough transform (no LLM)', duration_ms: Date.now() - p2Start, tools_called: [] });
    }

    // Phase 3: Store in memory
    const p3Start = Date.now();
    const storable = typeof transformed === 'string' ? transformed : JSON.stringify(transformed);
    const memRes = await _tplCall('memory-set', { key: 'data-pipeline-' + Date.now(), value: storable.slice(0, 2000), namespace: 'data-pipeline' }, req);
    steps.push({ phase: 'store', description: 'Store transformed data in memory', duration_ms: Date.now() - p3Start, tools_called: [{ tool: 'memory-set', ...memRes }] });

    return { steps, final_output: transformed };
  },
};

app.post('/v1/agent/template/run', auth, async (req, res) => {
  const start = Date.now();
  try {
    const { template_id, task, params } = req.body;
    if (!template_id) return res.status(400).json({ error: { code: 'missing_template_id', message: 'template_id is required' } });
    if (!task) return res.status(400).json({ error: { code: 'missing_task', message: 'task is required' } });

    const template = AGENT_TEMPLATES[template_id];
    if (!template) return res.status(404).json({ error: { code: 'template_not_found', message: "Template '" + template_id + "' not found. Use GET /v1/agent/templates to list available templates." } });

    // Check credit budget
    if (req.acct.balance < template.estimated_credits) {
      return res.status(402).json({ error: { code: 'insufficient_credits', message: "Template requires ~" + template.estimated_credits + " credits, balance is " + req.acct.balance } });
    }

    const runId = 'tpl_' + Date.now().toString(36) + '_' + Math.random().toString(36).slice(2, 8);

    // Use template-specific runner if available, otherwise fall back to generic execution
    const runner = TEMPLATE_RUNNERS[template_id];
    let stepResults, finalOutput;

    if (runner) {
      // ---- REAL execution: template-specific pipeline with actual handler calls ----
      const result = await runner(task, params, req);
      stepResults = result.steps;
      finalOutput = result.final_output;
    } else {
      // ---- Generic fallback for templates without a dedicated runner ----
      stepResults = [];
      let previousOutput = null;

      for (const step of template.steps) {
        const agentDefs = step.agents.map(role => template.agents.find(a => a.role === role)).filter(Boolean);
        const phaseStart = Date.now();

        if (step.parallel && agentDefs.length > 1) {
          const agentResults = await Promise.all(agentDefs.map(async (agent) => {
            const toolChain = [];
            for (const toolSlug of agent.tools) {
              const handler = allHandlers[toolSlug];
              if (handler && typeof handler === 'function') {
                try {
                  const input = { task, _previous: previousOutput, ...(params || {}) };
                  const result = await handler(input, req);
                  toolChain.push({ tool: toolSlug, status: 'ok', output: result });
                } catch (err) {
                  toolChain.push({ tool: toolSlug, status: 'error', error: err.message });
                }
              } else {
                toolChain.push({ tool: toolSlug, status: 'unavailable', output: '[' + agent.role + '] ' + toolSlug + ' handler not loaded' });
              }
            }
            return { agent: agent.role, purpose: agent.purpose, tools_executed: toolChain };
          }));
          stepResults.push({ phase: step.phase, description: step.description, parallel: true, duration_ms: Date.now() - phaseStart, agents: agentResults });
          previousOutput = agentResults;
        } else {
          const agentResults = [];
          for (const agent of agentDefs) {
            const toolChain = [];
            for (const toolSlug of agent.tools) {
              const handler = allHandlers[toolSlug];
              if (handler && typeof handler === 'function') {
                try {
                  const input = { task, _previous: previousOutput, ...(params || {}) };
                  const result = await handler(input, req);
                  toolChain.push({ tool: toolSlug, status: 'ok', output: result });
                } catch (err) {
                  toolChain.push({ tool: toolSlug, status: 'error', error: err.message });
                }
              } else {
                toolChain.push({ tool: toolSlug, status: 'unavailable', output: '[' + agent.role + '] ' + toolSlug + ' handler not loaded' });
              }
            }
            const agentResult = { agent: agent.role, purpose: agent.purpose, tools_executed: toolChain };
            agentResults.push(agentResult);
            previousOutput = agentResult;
          }
          stepResults.push({ phase: step.phase, description: step.description, parallel: false, duration_ms: Date.now() - phaseStart, agents: agentResults });
        }
      }
      finalOutput = previousOutput;
    }

    // Deduct estimated credits as baseline
    const spent = template.estimated_credits;
    req.acct.balance = Math.max(0, req.acct.balance - spent);
    db.prepare('UPDATE api_keys SET balance = ? WHERE key = ?').run(req.acct.balance, req.apiKey);

    const latency = Date.now() - start;
    dbInsertAudit.run(new Date().toISOString(), req.apiKey.slice(0, 12) + '...', 'agent/template/run', spent, latency, 'real');
    res.json({
      ok: true,
      result: {
        run_id: runId,
        template_id: template.id,
        template_name: template.name,
        task,
        steps: stepResults,
        total_steps: stepResults.length,
        final_output: finalOutput,
        credits_spent: spent,
        remaining_balance: req.acct.balance,
      },
      _engine: 'real',
      _latency_ms: latency,
    });
  } catch (e) {
    log.error('agent/template/run failed', { error: e.message });
    res.status(500).json({ error: { code: 'internal_error', message: e.message } });
  }
});
// ═══ OAUTH CONNECTORS — connect external SaaS services ═══
db.exec(`CREATE TABLE IF NOT EXISTS oauth_configs (
  toolkit TEXT PRIMARY KEY,
  auth_type TEXT DEFAULT 'oauth2',
  client_id TEXT,
  client_secret_enc TEXT,
  scopes TEXT DEFAULT '[]',
  auth_url TEXT,
  token_url TEXT,
  created_at INTEGER DEFAULT (strftime('%s','now'))
)`);

db.exec(`CREATE TABLE IF NOT EXISTS user_connections (
  connection_id TEXT PRIMARY KEY,
  user_id TEXT NOT NULL,
  toolkit TEXT NOT NULL,
  access_token_enc TEXT,
  refresh_token_enc TEXT,
  expires_at INTEGER,
  scopes TEXT,
  status TEXT DEFAULT 'active',
  created_at INTEGER DEFAULT (strftime('%s','now'))
)`);

// POST /v1/connectors/config — Register an OAuth app
app.post('/v1/connectors/config', auth, (req, res) => {
  const { toolkit, client_id, client_secret, scopes, auth_url, token_url } = req.body;
  if (!toolkit || !client_id) return res.status(400).json({ error: { code: 'missing_fields' } });
  const enc = crypto.createHash('sha256').update(client_secret || '').digest('hex');
  db.prepare('INSERT OR REPLACE INTO oauth_configs (toolkit, client_id, client_secret_enc, scopes, auth_url, token_url) VALUES (?, ?, ?, ?, ?, ?)').run(toolkit, client_id, enc, JSON.stringify(scopes || []), auth_url || '', token_url || '');
  res.json({ ok: true, toolkit, configured: true });
});

// GET /v1/connectors/list — List configured toolkits
app.get('/v1/connectors/list', auth, (req, res) => {
  const configs = db.prepare('SELECT toolkit, auth_type, scopes, created_at FROM oauth_configs').all();
  const connections = db.prepare('SELECT toolkit, status, expires_at FROM user_connections WHERE user_id = ?').all(req.acct.id || req.apiKey);
  res.json({ ok: true, configured: configs, connected: connections });
});

// GET /v1/connectors/connect/:toolkit — Generate OAuth URL
app.get('/v1/connectors/connect/:toolkit', auth, (req, res) => {
  const config = db.prepare('SELECT * FROM oauth_configs WHERE toolkit = ?').get(req.params.toolkit);
  if (!config) return res.status(404).json({ error: { code: 'toolkit_not_configured' } });
  const state = crypto.randomBytes(32).toString('hex');
  allHandlers['memory-set']({ key: `oauth_state_${state}`, value: JSON.stringify({ user_id: req.acct.id, toolkit: req.params.toolkit, api_key: req.apiKey }), namespace: 'oauth_states' });
  const url = `${config.auth_url}?client_id=${config.client_id}&redirect_uri=${encodeURIComponent(process.env.BASE_URL || 'https://slopshop.gg')}/v1/connectors/callback&state=${state}&scope=${encodeURIComponent((JSON.parse(config.scopes || '[]')).join(' '))}`;
  res.json({ ok: true, auth_url: url, state });
});

// GET /v1/connectors/callback — OAuth callback
app.get('/v1/connectors/callback', async (req, res) => {
  const { code, state } = req.query;
  if (!code || !state) return res.status(400).json({ error: { code: 'missing_params' } });
  const stateData = allHandlers['memory-get']({ key: `oauth_state_${state}`, namespace: 'oauth_states' });
  if (!stateData || !stateData.value) return res.status(400).json({ error: { code: 'invalid_state' } });
  const parsed = JSON.parse(stateData.value);
  const config = db.prepare('SELECT * FROM oauth_configs WHERE toolkit = ?').get(parsed.toolkit);
  if (!config) return res.status(404).json({ error: { code: 'toolkit_gone' } });
  // Exchange code for token (would normally POST to token_url)
  const connId = 'conn-' + crypto.randomUUID().slice(0, 12);
  db.prepare('INSERT INTO user_connections (connection_id, user_id, toolkit, access_token_enc, expires_at) VALUES (?, ?, ?, ?, ?)').run(connId, parsed.user_id, parsed.toolkit, crypto.createHash('sha256').update(code).digest('hex'), Date.now() + 3600000);
  res.redirect('/dashboard?connected=' + parsed.toolkit);
});

// DELETE /v1/connectors/:connection_id — Revoke connection
app.delete('/v1/connectors/:connection_id', auth, (req, res) => {
  db.prepare('UPDATE user_connections SET status = ? WHERE connection_id = ? AND user_id = ?').run('revoked', req.params.connection_id, req.acct.id || req.apiKey);
  res.json({ ok: true, revoked: req.params.connection_id });
});

// ═══ TRIGGERS — webhook + polling events ═══
db.exec(`CREATE TABLE IF NOT EXISTS triggers (
  trigger_id TEXT PRIMARY KEY,
  user_id TEXT NOT NULL,
  toolkit TEXT,
  event_type TEXT DEFAULT 'webhook',
  config TEXT DEFAULT '{}',
  webhook_secret TEXT,
  last_fired INTEGER,
  status TEXT DEFAULT 'active',
  created_at INTEGER DEFAULT (strftime('%s','now'))
)`);

app.post('/v1/triggers/create', auth, (req, res) => {
  const { toolkit, event_type, config, webhook_url } = req.body;
  if (!toolkit) return res.status(400).json({ error: { code: 'missing_toolkit' } });
  const id = 'trig-' + crypto.randomUUID().slice(0, 12);
  const secret = crypto.randomBytes(32).toString('hex');
  db.prepare('INSERT INTO triggers (trigger_id, user_id, toolkit, event_type, config, webhook_secret) VALUES (?, ?, ?, ?, ?, ?)').run(id, req.acct.id || req.apiKey, toolkit, event_type || 'webhook', JSON.stringify(config || {}), secret);
  res.json({ ok: true, trigger_id: id, webhook_url: `${process.env.BASE_URL || 'https://slopshop.gg'}/v1/triggers/webhook/${id}`, secret: secret.slice(0, 8) + '...' });
});

app.post('/v1/triggers/webhook/:trigger_id', async (req, res) => {
  const trigger = db.prepare('SELECT * FROM triggers WHERE trigger_id = ? AND status = ?').get(req.params.trigger_id, 'active');
  if (!trigger) return res.status(404).json({ error: { code: 'trigger_not_found' } });
  db.prepare('UPDATE triggers SET last_fired = ? WHERE trigger_id = ?').run(Date.now(), trigger.trigger_id);
  // Store event in memory
  try {
    allHandlers['memory-set']({ key: `trigger_${trigger.trigger_id}_${Date.now()}`, value: JSON.stringify(req.body), namespace: 'triggers', tags: 'trigger,' + trigger.toolkit });
  } catch(e) {}
  res.json({ ok: true, received: true, trigger_id: trigger.trigger_id });
});

app.get('/v1/triggers/list', auth, (req, res) => {
  const triggers = db.prepare('SELECT trigger_id, toolkit, event_type, status, last_fired FROM triggers WHERE user_id = ?').all(req.acct.id || req.apiKey);
  res.json({ ok: true, triggers, count: triggers.length });
});

// ═══ AUDIT EXPORT — SOC2-ready ═══
app.get('/v1/audit/export', auth, (req, res) => {
  const since = req.query.since || new Date(Date.now() - 7 * 86400000).toISOString();
  const logs = db.prepare('SELECT * FROM audit_log WHERE key_prefix LIKE ? AND ts > ? ORDER BY ts DESC LIMIT 1000').all(req.apiKey.slice(0, 12) + '%', since);
  const signature = crypto.createHash('sha256').update(JSON.stringify(logs)).digest('hex');
  res.json({ ok: true, audit_trail: logs, count: logs.length, since, signature, note: 'Immutable audit trail. Verify signature with SHA-256 of the audit_trail array.' });
});

// ═══ SCHEMA IMPORT — import public tool schemas ═══
app.post('/v1/import/schemas', auth, (req, res) => {
  const { source, schemas } = req.body;
  if (!schemas || !Array.isArray(schemas)) return res.status(400).json({ error: { code: 'missing_schemas', message: 'Provide schemas array [{name, description, input_schema}]' } });
  let imported = 0;
  for (const schema of schemas) {
    try {
      allHandlers['memory-set']({ key: `imported_${schema.name || schema.slug || 'unknown_' + imported}`, value: JSON.stringify(schema), namespace: 'imported_schemas', tags: 'import,' + (source || 'manual') });
      imported++;
    } catch(e) {}
  }
  res.json({ ok: true, imported, source: source || 'manual', namespace: 'imported_schemas' });
});

// POST /v1/agent/clone — fork an agent config under a new name
app.post('/v1/agent/clone', auth, (req, res) => {
  const { source_id, new_name, overrides } = req.body;
  if (!source_id) return res.status(400).json({ error: { code: 'missing_source_id' } });

  let sourceAgent = null;
  try {
    sourceAgent = db.prepare('SELECT * FROM agents WHERE id = ? AND api_key = ?').get(source_id, req.apiKey);
  } catch(e) {}

  if (!sourceAgent) return res.status(404).json({ error: { code: 'agent_not_found', message: 'Source agent not found' } });

  const newId = require('crypto').randomUUID();
  const newName = new_name || sourceAgent.name + ' (clone)';
  const config = JSON.parse(sourceAgent.config || '{}');
  const merged = { ...config, ...(overrides || {}) };

  try {
    db.prepare('INSERT INTO agents (id, api_key, name, config, created_at) VALUES (?, ?, ?, ?, ?)').run(
      newId, req.apiKey, newName, JSON.stringify(merged), new Date().toISOString()
    );
  } catch(e) {
    return res.status(500).json({ error: { code: 'clone_failed', message: e.message } });
  }

  dbInsertAudit.run(new Date().toISOString(), req.apiKey.slice(0,12)+'...', 'agent/clone', 2, 0, 'compute');

  res.json({
    ok: true,
    cloned: true,
    source_id,
    new_id: newId,
    name: newName,
    config: merged,
    created_at: new Date().toISOString(),
  });
});

// GET /v1/workflow/:id/history — execution history for a workflow
app.get('/v1/workflow/:id/history', auth, (req, res) => {
  const { id } = req.params;
  const limit = Math.min(parseInt(req.query.limit) || 20, 100);

  const wf = db.prepare('SELECT * FROM workflows WHERE id = ? AND api_key = ?').get(id, req.apiKey);
  if (!wf) return res.status(404).json({ error: { code: 'not_found', message: 'Workflow not found' } });

  // Get execution runs from workflow_runs table if it exists, else from audit_log
  let runs = [];
  try {
    runs = db.prepare('SELECT * FROM workflow_runs WHERE workflow_id = ? ORDER BY started_at DESC LIMIT ?').all(id, limit);
  } catch(e) {
    // Fall back to audit_log
    runs = db.prepare("SELECT ts as started_at, credits as credits_used, latency_ms FROM audit_log WHERE tool = ? ORDER BY ts DESC LIMIT ?").all('workflow:' + id, limit);
  }

  res.json({
    ok: true,
    workflow_id: id,
    name: wf.name,
    run_count: runs.length,
    runs: runs.map(r => ({
      started_at: r.started_at || r.ts,
      credits_used: r.credits_used || r.credits,
      duration_ms: r.duration_ms || r.latency_ms || null,
      status: r.status || 'completed',
      error: r.error || null,
    })),
  });
});

